+    private static func resetLine(_ reset: String) -> String {
+        let trimmed = reset.trimmingCharacters(in: .whitespacesAndNewlines)
+        if trimmed.lowercased().hasPrefix("resets") { return trimmed }
+        return "Resets \(trimmed)"
+    }
